// // This module selects signal B when SEL is LOW (0) and signal A when SEL is HIGH (1)
module top_module(
    A   ,
    B   ,
    SEL ,
    OUT 
);input A   ;
    input B   ;
    input SEL ;
    output reg OUT ;

    always @(SEL or A or B)
    begin
        if (SEL == 0)
            OUT = A;
        else
            OUT = B;
    end

endmodule
